struct elfhdr {
	uint magic;  // must equal ELF_MAGIC
	uchar elf[12];
	ushort type;
	ushort machine;
	uint version;
	uint64 entry;
	uint64 phoff;
	uint64 shoff;
	uint flags;
	ushort ehsize;
	ushort phentsize;
	ushort phnum;
	ushort shentsize;
	ushort shnum;
	ushort shstrndx;
}

struct proghdr {
	uint32 type;
	uint32 flags;
	uint64 off;
	uint64 vaddr;
	uint64 paddr;
	uint64 filesz;
	uint64 memsz;
	uint64 align;
}

int main(int argc, char* argv[]) {
	struct elfhdr elf;
	struct proghdr ph;
	int had_write = 0;
	char a = 0;
	if (argc != 3) {
		printf("the arg number error!\n");
		return 1;
	}
	FILE* f = fopen(argv[1], "rb");  // 输入文件
	FILE* g = fopen(argv[2], "wb");  // 输出文件
	if (!f) {
		printf("fopen error!\n");
		return 1;
	}
	if (fread(&elf, 1, sizeof(elf), f) != sizeof(elf)) {
		printf("read elf_header error!\n");
		return 1;
	}
	for (int i = 0; i < elf.phnum; i++) {
		fseek(f, elf.phoff + i * sizeof(ph), SEEK_SET);
		if (fread(&ph, 1, sizeof(ph), f) != sizeof(ph)) {
			printf("read ph_header error!\n");
			return 1;
		}
		if (ph.type != 1) {   // 1 = ELF_PROG_LOAD 
			continue;
		}
		fseek(f, ph.off, SEEK_SET);
		char* buffer = (char*)malloc(ph.filesz);
		fread(buffer, 1, ph.filesz, f);
		for (int j = 0;j < ph.vaddr - had_write;++j) {  // 刷0，感觉这方法好傻
			fwrite(&a, 1, 1, g);
		}
		fwrite(buffer, 1, ph.filesz, g);
		for (int j = 0;j < ph.memsz - ph.filesz;++j) {
			fwrite(&a, 1, 1, g);
		}
		had_write = ph.vaddr + ph.memsz;
		free(buffer);
	}
	fclose(f);
	fclose(g);
	return 0;
}

fn main() {
    let out_dir = PathBuf::from(env::var("OUT_DIR").unwrap());

    // Put the linker script somewhere the linker can find it
    fs::File::create(out_dir.join("link-k210.ld"))
        .unwrap()
        .write_all(include_bytes!("link-k210.ld"))
        .unwrap();
    println!("cargo:rustc-link-search={}", out_dir.display());

    println!("cargo:rerun-if-changed=build.rs");
    println!("cargo:rerun-if-changed=link-k210.ld");
}

