      goto bad;
    ustack[argc] = sp;
  }
  ustack[argc] = 0;

  // push the array of argv[] pointers.
  sp -= (argc+1) * sizeof(uint64);
  sp -= sp % 16;
  if(sp < stackbase)
    goto bad;
  if(copyout(pagetable, sp, (char *)ustack, (argc+1)*sizeof(uint64)) < 0)
    goto bad;

  sp1 = sp;
// yinxunjian------------
  // Push argument strings, prepare rest of stack in ustack.
  for(envc = 0; envp[envc]; envc++) {
    if(envc >= MAXARG)
      goto bad;
    sp -= strlen(envp[envc]) + 1;
    sp -= sp % 16; // riscv sp must be 16-byte aligned
    if(sp < stackbase)
      goto bad;
    if(copyout(pagetable, sp, envp[envc], strlen(envp[envc]) + 1) < 0)
      goto bad;
    ustack[envc] = sp;
  }
  ustack[envc] = 0;

  // push the array of envp[] pointers.
  sp -= (envc+1) * sizeof(uint64);
  sp -= sp % 16;
  if(sp < stackbase)
    goto bad;
  if(copyout(pagetable, sp, (char *)ustack, (envc+1)*sizeof(uint64)) < 0)
    goto bad;

// end---------------

  // arguments to user main(argc, argv, envp)
  // argc is returned via the system call return
  // value, which goes in a0.
  p->trapframe->a1 = sp1;
  p->trapframe->a2 = sp;

  // Save program name for debugging.
  for(last=s=path; *s; s++)
    if(*s == '/')
      last = s+1;
  safestrcpy(p->name, last, sizeof(p->name));

  // Commit to the user image.
