}

uint64
sys_openat(void)
{
  int dirfd;
  char path[FAT32_MAX_PATH];
  char absolute_path[FAT32_MAX_PATH];
  char *s;
  int flags;
  int mode;
  int len;

  struct dirent *de;
  if(argint(0, &dirfd) < 0 || argstr(1, path, FAT32_MAX_PATH) < 0 || argint(2, &flags) < 0 || argint(3, &mode) < 0)
    return -1;
  if(path[0] == '/') // absolute path
    return fopen(path, flags);
  else if(dirfd == -100) // AT_CWDFD = -100
    de = myproc()->cwd; 
  else
    de = myproc()->ofile[dirfd]->ep;

  s = absolute_path + FAT32_MAX_PATH - 1;
  *s = '\0';
  len = strlen(path);
  s -= len;
  strncpy(s, path, len);
  while (de->parent) {
    len = strlen(de->filename);
    s -= len;
    if (s <= absolute_path)          // can't reach root "/"
      return 0;
    strncpy(s, de->filename, len);
    *--s = '/';
    de = de->parent;
  }
  return fopen(s, flags);
}

