uint64
sys_mmap(void)
{
  uint64 addr;
  int length, prot, flags, fd, offset;
  if(argaddr(0, &addr) < 0 || argint(1, &length) < 0 || argint(2, &prot) < 0 ||
     argint(3, &flags) < 0 || argint(4, &fd) < 0 || argint(5, &offset) < 0)
    return -1;

  struct proc *p = myproc();
  struct file *f = p->ofile[fd];
  if(((prot&PROT_READ) && !f->readable) ||
     ((prot&PROT_WRITE) && !f->writable && !(flags&MAP_PRIVATE)))
    return -1;

  struct vma *pvma;
  for(pvma = vmatable; pvma < &vmatable[NVMA]; pvma++){
    acquire(&pvma->lock);
    if(pvma->len == 0)
      break;
    release(&pvma->lock);
  }
  pvma->next = 0;
  pvma->len = length;
  pvma->flags = flags;
  pvma->prot = prot;
  pvma->off = offset;
  pvma->file = f;
  filedup(f);

  struct vma *t = p->vma;
  if(!t){
    pvma->start = VMA_START;
    pvma->end = VMA_START + length;
    p->vma = pvma;
  } else {
    while(t->next)
      t = t->next;
    pvma->start = PGROUNDUP(t->end);
    pvma->end = pvma->start + length;
    t->next = pvma;
  }
  addr = pvma->start;
  release(&pvma->lock);
  return addr;
}

uint64
sys_munmap(void)
{
  uint64 addr;
  int length;
  if(argaddr(0, &addr) < 0 || argint(1, &length) < 0)
    return -1;

  struct proc *p = myproc();
  struct vma *v = p->vma;
  struct vma *pre = 0;
  while(v){
    if(addr >= v->start && addr < v->end)
      break;
    pre = v;
    v = v->next;
  }

  if(!v)
    return -1;
  //if(v->flags == MAP_SHARED && walkaddr(p->pagetablse, addr))
    //writeback(v, addr, length);
  if(addr == v->start){
    if(length == v->len){
      if(walkaddr(p->pagetable, addr))
        vmunmap(p->pagetable, addr, PGROUNDUP(length)/PGSIZE, 1);
      fileclose(v->file);
      if(pre)
        pre->next = v->next;
      else
        p->vma = v->next;
      acquire(&v->lock);
      v->next = 0;
      v->file = 0;
      v->len = 0;
      v->flags = 0;
      v->prot = 0;
      v->start = 0;
      v->end = 0;
      v->off = 0;
      release(&v->lock);
    } else {
      if(walkaddr(p->pagetable, addr))
        vmunmap(p->pagetable, addr, length/PGSIZE, 1);
      v->start += length;
      v->off += length;
      v->len -= length;
    }
  } else {
    if(walkaddr(p->pagetable, PGROUNDUP(addr)))
      vmunmap(p->pagetable, PGROUNDUP(addr), length/PGSIZE, 1);
    v->len -= length;
    v->end -= length;
  }
  return 0;
}

uint64
sys_mount(void){
  char special[FAT32_MAX_PATH],dir[FAT32_MAX_PATH],fstype[FAT32_MAX_PATH];
