  if(argstr(0, special, FAT32_MAX_PATH) < 0||argstr(1, dir, FAT32_MAX_PATH) < 0||argstr(2, fstype, FAT32_MAX_PATH) < 0||argint(3, &flags) < 0||argaddr(4, &data) < 0) 
    return -1;

  struct dirent *mydir;
  if((mydir = ename(dir)) == 0){
    return -1;
  }
  elock(mydir);
  mydir->attribute |= 0x40;
  if(emount(dir, NULL) == -1){
      mydir->attribute &= ~0x40;
      return -1;
  }
  eunlock(mydir);
  return 0;
}

