uint64 sys_clock_gettime(void)
{
  int clkid;
  uint64 *ts;
  uint64 temp;
  if(argint(0, &clkid) < 0 || argaddr(1, (uint64*)&ts) < 0)
    return -1;
  if(clkid == 0)  //CLOCK_REALTIME = 0
  {
    temp=r_time();
    ts[0] = temp/32768;
    ts[1] = (temp%32768)*1000000/32768;
    return 0;
  }
  else if(clkid == 1) //CLOCK_MONOTONIC = 1
    temp=10*ticks;
  else if(clkid == 2) //CLOCK_PROCESS_CPUTIME_ID = 2
  {
    struct proc *p = myproc();
    temp = p->utime + p->stime;
  }
  else
    return -1;
  ts[0] = temp/1000000;
  ts[1] = temp%1000000;
  return 0;
}

